// ---- Cursor ----
const cursor = document.getElementById('cursor');
const follower = document.getElementById('cursorFollower');
let mx = 0, my = 0, fx = 0, fy = 0;

document.addEventListener('mousemove', e => {
  mx = e.clientX; my = e.clientY;
  cursor.style.left = mx + 'px';
  cursor.style.top = my + 'px';
});

(function animF() {
  fx += (mx - fx) * 0.12;
  fy += (my - fy) * 0.12;
  follower.style.left = fx + 'px';
  follower.style.top = fy + 'px';
  requestAnimationFrame(animF);
})();

// ---- Nav scroll ----
window.addEventListener('scroll', () => {
  document.getElementById('mainNav').classList.toggle('scrolled', scrollY > 40);
});

// ---- Cookie ----
setTimeout(() => document.getElementById('cookieBanner').classList.add('visible'), 1800);

function closeCookie() {
  document.getElementById('cookieBanner').classList.remove('visible');
}

// ---- Reveal on scroll ----
document.querySelectorAll('.reveal').forEach(r => {
  new IntersectionObserver((entries) => {
    entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
  }, { threshold: 0.1 }).observe(r);
});

// ---- Filter ----
function filterProducts(btn, cat) {
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.product-card').forEach(card => {
    card.style.display = (cat === 'all' || card.dataset.cat === cat) ? '' : 'none';
  });
}

// ---- Cart ----
const CART_IMAGES = {
  'T-Shirt Performance Blanc': 'data:image/png;base64,',
  'T-Shirt Run Essential':     'data:image/png;base64,',
  'T-Shirt Long Performance':  'data:image/jpeg;base64,'
};

let cartItems = [];
let cartCount = 0;

function addToCart(name, price) {
  const existing = cartItems.find(i => i.name === name);
  if (existing) existing.qty++;
  else cartItems.push({ name, price, qty: 1 });
  cartCount++;
  document.getElementById('cartCount').textContent = cartCount;
  showToast('\u2713 ' + name + ' ajouté !');
  renderCart();
}

function renderCart() {
  const el = document.getElementById('cartItems');
  const total = document.getElementById('cartTotal');
  if (!cartItems.length) {
    el.innerHTML = '<p style="color:var(--gray);font-size:.9rem;text-align:center;padding:40px 0;">Votre panier est vide.</p>';
    total.style.display = 'none';
    return;
  }
  el.innerHTML = cartItems.map(i => `
    <div class="cart-item">
      <div class="cart-item-img">${CART_IMAGES[i.name] ? `<img src="${CART_IMAGES[i.name]}" alt="${i.name}">` : ''}</div>
      <div class="cart-item-info">
        <h4>${i.name}</h4>
        <p>Qté: ${i.qty} · ${i.price * i.qty} €</p>
      </div>
    </div>`).join('');
  total.style.display = 'flex';
  document.getElementById('totalPrice').textContent = cartItems.reduce((a, i) => a + i.price * i.qty, 0) + ' €';
}

function openCart() {
  document.getElementById('cartModal').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeCart() {
  document.getElementById('cartModal').classList.remove('open');
  document.body.style.overflow = '';
}

function closeCartOutside(e) {
  if (e.target === document.getElementById('cartModal')) closeCart();
}

function checkout() {
  closeCart();
  showToast('\ud83c\udf89 Commande simulée ! Merci !');
  cartItems = [];
  cartCount = 0;
  document.getElementById('cartCount').textContent = 0;
  renderCart();
}

function showToast(msg) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(() => t.classList.remove('show'), 2800);
}

function submitForm() {
  document.getElementById('contactForm').style.display = 'none';
  document.getElementById('formSuccess').style.display = 'block';
}